// bit l set when feature[split[l]] > border[split[l]]
func evalTree(treeIdx int, f []float64) float64 {
	leafIdx := 0
	splitOffset := treeSplitOffset[treeIdx]
	depth := treeDepth[treeIdx]
	for l := 0; l < depth; l++ {
		s := splitOffset + l
		v := f[splitFeature[s]]
		bit := v > splitBorder[s]
		if math.IsNaN(v) {
			bit = splitNanTrue[s] == 1
		}
		if bit {
			leafIdx |= (1 << l)
		}
	}
	return leafValues[treeLeafOffset[treeIdx]+leafIdx]
}

// Predict returns the regression score for feature vector f.
func Predict(f []float64) float64 {
	s := 0.0
	for i := 0; i < treeCount; i++ {
		s += evalTree(i, f)
	}
	return bias + scale*s
}
